mapper.select:
SELECT a.id AS menu_id, a.id, a.menu_name, a.parent_id, a.order_num, a.path, a.component, a.query, a.is_frame, a.is_cache, a.menu_type, a.visible, a.status, a.data_type, a.menu_icon_color AS menuIconColor, CASE a.status WHEN '1' THEN '正常' ELSE '停用' END AS statusLabel, IFNULL(a.perms, '') AS perms, a.icon, a.create_time, CASE WHEN (SELECT COUNT(b.id) FROM sys_menu b WHERE b.parent_id = a.id) > 0 THEN '1' ELSE '0' END AS has_children, a.link
FROM sys_menu a WHERE 1 = 1
FROM sys_menu a INNER JOIN sys_role_menu b ON b.menu_id = a.id INNER JOIN sys_role_user c ON c.role_id = b.role_id WHERE c.user_id = #{userId}
AND a.menu_name LIKE #{menuNameLike, jdbcType=VARCHAR}
AND a.parent_id = 0
AND a.status = #{status}
ORDER BY a.parent_id, a.order_num

SELECT a.id, a.id AS menuId, a.menu_name, a.parent_id, a.order_num, a.path, a.component, a.query, a.is_frame, a.link, a.is_cache, a.menu_type, a.visible, a.status, a.perms, a.icon, a.create_by, a.create_by_name, a.create_time, a.update_by, a.update_by_name, a.update_time, a.remark, a.menu_icon_color, a.data_type, CASE a.status WHEN '1' THEN '在用' ELSE '停用' END AS status_label, CASE a.menu_type WHEN 'C' THEN '菜单' WHEN 'M' THEN '目录' ELSE '按钮' END AS menu_type_label, CASE WHEN (SELECT COUNT(b.id) FROM sys_menu b WHERE b.parent_id = a.id) > 0 THEN '1' ELSE '0' END AS has_children
FROM sys_menu a WHERE a.parent_id = #{parentGid}
FROM sys_menu a INNER JOIN sys_role_menu b ON b.menu_id = a.id INNER JOIN sys_role_user c ON c.role_id = b.role_id WHERE a.parent_id = #{parentGid} AND c.user_id = #{userId}
ORDER BY a.order_num
